class FenwickTree:
    def __init__(self, size):
        self.size = size
        self.tree = [0] * (size + 1)

    def update(self, index, delta):
        while index <= self.size:
            self.tree[index] += delta
            index += index & (-index)

    def query(self, index):
        _sum = 0
        while index > 0:
            _sum += self.tree[index]
            index -= index & (-index)
        return _sum

def count_inversions(arr):
    if not arr or len(arr) < 2:
        return 0

    unique_elements = sorted(list(set(arr)))
    rank_map = {val: i + 1 for i, val in enumerate(unique_elements)}
    compressed_arr = [rank_map[x] for x in arr]

    max_rank = len(unique_elements)
    ft = FenwickTree(max_rank)

    inversions_count = 0

    for rank in compressed_arr:
        inversions_count += ft.query(ft.size) - ft.query(rank)
        ft.update(rank, 1)

    return inversions_count
